def create_local_app_folder(local_app_path):
    if exists(local_app_path):
        raise ValueError("There is already a '%s' folder! Aborting!" % local_app_path)
    for folder in subfolders(local_app_path):
        if not exists(folder):
            os.mkdir(folder)
            init_path = join(folder, '__init__.py')
            if not exists(init_path):
                create_file(init_path)

def create_file(filepath, content=''):
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(content)

def deprecated(obj):
    if isinstance(obj, type):
        return _deprecated_cls(cls=obj)
    else:
        return _deprecated_func(f=obj)

def _deprecated_func(f, warn_cls=RemovedInOscar32Warning):

    def _deprecated(*args, **kwargs):
        message = "Method '%s' is deprecated and will be removed in the next version of django-oscar" % f.__name__
        warnings.warn(message, warn_cls, stacklevel=2)
        return f(*args, **kwargs)
    return _deprecated

def _deprecated_cls(cls, warn_cls=RemovedInOscar32Warning):

    class Deprecated(cls):

        def __init__(self, *args, **kwargs):
            message = "Class '%s' is deprecated and will be removed in the next version of django-oscar" % cls.__name__
            warnings.warn(message, warn_cls, stacklevel=2)
            super().__init__(*args, **kwargs)
    return Deprecated

def _deprecated(*args, **kwargs):
    message = "Method '%s' is deprecated and will be removed in the next version of django-oscar" % f.__name__
    warnings.warn(message, warn_cls, stacklevel=2)
    return f(*args, **kwargs)

@lru_cache(maxsize=100)
def get_class_loader():
