def datetime_combine(date, time):
    """Timezone aware version of `datetime.datetime.combine`"""
    return make_aware(datetime.datetime.combine(date, time), get_current_timezone())

def safe_referrer(request, default):
    """
    Takes the request and a default URL. Returns HTTP_REFERER if it's safe
    to use and set, and the default URL otherwise.

    The default URL can be a model with get_absolute_url defined, a urlname
    or a regular URL
    """
    referrer = request.META.get('HTTP_REFERER')
    if referrer and url_has_allowed_host_and_scheme(referrer, request.get_host()):
        return referrer
    if default:
        return resolve_url(default)
    else:
        return default

def non_whitespace(value):
    stripped = value.strip()
    if not stripped:
        raise ValidationError(_('This field is required'))
    return stripped

def non_python_keyword(value):
    if keyword.iskeyword(value):
        raise ValidationError(_('This field is invalid as its value is forbidden'))
    return value

def __init__(self, *args, **kwargs):
    self.is_local_url = False
    super().__init__(*args, **kwargs)

def __call__(self, value):
    try:
        super().__call__(value)
    except ValidationError:
        if value:
            self.validate_local_url(value)
        else:
            raise

def _validate_url(self, value):
    try:
        resolve(value)
    except Http404:
        FlatPage = get_model('flatpages', 'FlatPage')
        if FlatPage is not None:
            try:
                FlatPage.objects.get(url=value)
            except FlatPage.DoesNotExist:
                self.is_local_url = True
            else:
                return
        raise ValidationError(_('The URL "%s" does not exist') % value)
    else:
        self.is_local_url = True

def validate_local_url(self, value):
    value = self.clean_url(value)
    urlconf = get_urlconf()
    i18n_patterns_used, _ = is_language_prefix_patterns_used(urlconf)
    redefined_language = None
    if i18n_patterns_used:
        language = get_language_from_path(value)
        current_language = get_language()
        if language != current_language:
            redefined_language = language
    if redefined_language:
        with override(redefined_language):
            self._validate_url(value)
    else:
        self._validate_url(value)

def clean_url(self, value):
    """
        Ensure url has a preceding slash and no query string
        """
    if value != '/':
        value = '/' + value.lstrip('/')
    q_index = value.find('?')
    if q_index > 0:
        value = value[:q_index]
    return value

