def optgroups(self, name, value, attrs=None):
    """
        Borrowed liberally from https://github.com/applegrew/django-select2

        For model choice fields, return only the selected options. The rest
        will be populated with AJAX.
        """
    default = (None, [], 0)
    groups = [default]
    has_selected = False
    selected_choices = {force_str(v) for v in value}
    if not self.is_required and (not self.allow_multiple_selected):
        default[1].append(self.create_option(name, '', '', False, 0))
    if not isinstance(self.choices, ModelChoiceIterator):
        return super().optgroups(name, value, attrs=attrs)
    selected_choices = {c for c in selected_choices if c not in self.choices.field.empty_values}
    choices = ((obj.pk, force_str(obj)) for obj in self.choices.queryset.filter(pk__in=selected_choices))
    for option_value, option_label in choices:
        selected = str(option_value) in value and (has_selected is False or self.allow_multiple_selected)
        if selected is True and has_selected is False:
            has_selected = True
        index = len(default[1])
        subgroup = default[1]
        subgroup.append(self.create_option(name, option_value, option_label, selected_choices, index))
    return groups

def __init__(self, attrs=None):
    super().__init__(attrs)
    self.choices = (('unknown', _('---------')), ('true', _('Yes')), ('false', _('No')))

@register.simple_tag
def basket_form(request, product, quantity_type='single'):
    if not isinstance(product, Product):
        return ''
    initial = {}
    if not product.is_parent:
        initial['product_id'] = product.id
    form_class = AddToBasketForm
    if quantity_type == QNT_SINGLE:
        form_class = SimpleAddToBasketForm
    basket_post_data = request.session.pop('add_to_basket_form_post_data_%s' % product.pk, None)
    if basket_post_data is not None:
        basket_post_data = JSONSerializer().loads(basket_post_data.encode('latin-1'))
    form = form_class(request.basket, data=basket_post_data, product=product, initial=initial)
    return form

@register.simple_tag(name='category_tree')
def get_annotated_list(depth=None, parent=None):
    """
    Gets an annotated list from a tree branch.

    Borrows heavily from treebeard's get_annotated_list
    """
    max_depth = depth
    annotated_categories = []
    tree_slug = ''
    start_depth, prev_depth = (None, None)
    if parent:
        categories = parent.get_descendants()
        tree_slug = parent.get_full_slug()
        if max_depth is not None:
            max_depth += parent.get_depth()
    else:
        categories = Category.get_tree()
    if max_depth is not None:
        categories = categories.filter(depth__lte=max_depth)
    categories = categories.for_menu()
    info = CheapCategoryInfo(parent, url='')
    node_depth = 0
    for node in categories:
        node_depth = node.get_depth()
        if start_depth is None:
            start_depth = node_depth
        if prev_depth is None or node_depth > prev_depth:
            info['has_children'] = True
            if info.category is not None:
                tree_slug = info.category.get_full_slug(tree_slug)
        if prev_depth is not None and node_depth < prev_depth:
            depth_difference = prev_depth - node_depth
            info['num_to_close'] = list(range(0, depth_difference))
            tree_slugs = tree_slug.rsplit(node._slug_separator, depth_difference)
            if tree_slugs:
                tree_slug = tree_slugs[0]
            else:
                tree_slug = node.slug
        info = CheapCategoryInfo(node, url=node._get_absolute_url(tree_slug), num_to_close=[], level=node_depth - start_depth)
        annotated_categories.append(info)
        prev_depth = node_depth
    if prev_depth is not None:
        info['num_to_close'] = list(range(0, prev_depth - start_depth))
        info['has_children'] = node_depth > prev_depth
    return annotated_categories

