@register.simple_tag(takes_context=True)
def get_back_button(context):
    """
    Show back button, custom title available for different urls, for
    example 'Back to search results', no back button if user came from other
    site
    """
    request = context.get('request', None)
    if not request:
        raise Exception('Cannot get request from context')
    referrer = request.META.get('HTTP_REFERER', None)
    if not referrer:
        return None
    try:
        url = parse.urlparse(referrer)
    except (ValueError, TypeError):
        return None
    if request.get_host() != url.netloc:
        try:
            Site.objects.get(domain=url.netloc)
        except Site.DoesNotExist:
            return None
    try:
        match = resolve(url.path)
    except Resolver404:
        return None
    titles = {'search:search': _('Back to search results')}
    title = titles.get(match.view_name, None)
    if title is None:
        return None
    return {'url': referrer, 'title': str(title), 'match': match}

def do_dynamic_image_url(parser, token):
    tokens = token.split_contents()
    if len(tokens) < 2:
        raise template.TemplateSyntaxError('%r tag requires at least an image URL or field' % tokens[0])
    image = tokens[1]
    if len(tokens) > 2:
        params = tokens[2:]
    else:
        params = []
    return DynamicImageNode(image, params)

def __init__(self, image, params):
    self.image = image
    self.params = {}
    for p in params:
        try:
            bits = p.split('=')
            self.params[bits[0]] = template.Variable(bits[1])
        except IndexError:
            raise template.TemplateSyntaxError("image tag parameters must be of form key=value, you used '%s'" % p)

def render(self, context):
    if isinstance(self.image, ImageFieldFile):
        path = self.image.name
    else:
        path = self.image
    host = getattr(settings, 'DYNAMIC_MEDIA_URL', None)
    if host:
        params = []
        ext = path[path.rfind('.') + 1:]
        ext_changed = False
        for key, v in self.params.items():
            value = v.resolve(context)
            if key == 'format':
                ext = value
                ext_changed = True
            else:
                params.append('%s-%s' % (key, value))
        if len(params) > 0:
            suffix = '_'.join(params)
            path = '.'.join((path, suffix, ext))
        elif ext_changed:
            if params:
                path = '.'.join((path, ext))
            else:
                path = '.'.join((path, 'to', ext))
        return host + path

def render(self, context):
    try:
        return self._render(context)
    except Exception as e:
        if getattr(settings, 'OSCAR_THUMBNAIL_DEBUG', settings.DEBUG):
            raise e
        logger.exception(e)
        return ''

def _render(self, context):
    source = self.source_var.resolve(context)
    options = self.get_thumbnail_options(context)
    for key, expr in self.options:
        value = self.no_resolve.get(str(expr), expr.resolve(context))
        options[key] = value
    thumbnailer = get_thumbnailer()
    thumbnail = thumbnailer.generate_thumbnail(source, **options)
    if self.context_name is None:
        return escape(thumbnail.url)
    else:
        context[self.context_name] = thumbnail
        return ''

