    return self._strategy

def all_lines(self):
    """
        Return a cached set of basket lines.

        This is important for offers as they alter the line models and you
        don't want to reload them from the DB as that information would be
        lost.
        """
    if self.id is None:
        return self.lines.model.objects.none()
    if self._lines is None:
        self._lines = self.lines.select_related('product', 'stockrecord').prefetch_related('attributes', 'product__images').order_by(self._meta.pk.name)
    return self._lines

def max_allowed_quantity(self):
    """
        Returns maximum product quantity, that can be added to the basket
        with the respect to basket quantity threshold.
        """
    basket_threshold = settings.OSCAR_MAX_BASKET_QUANTITY_THRESHOLD
    if basket_threshold:
        total_basket_quantity = self.num_items
        max_allowed = basket_threshold - total_basket_quantity
        return (max_allowed, basket_threshold)
    return (None, None)

def is_quantity_allowed(self, qty, line=None):
    """
        Test whether the passed quantity of items can be added to the basket
        """
    max_allowed, basket_threshold = self.max_allowed_quantity()
    if line is not None:
        line_purchase_permitted, reason = line.purchase_info.availability.is_purchase_permitted(qty)
        if not line_purchase_permitted:
            return (line_purchase_permitted, reason)
        total_lines_quantity = self.basket_quantity(line) + qty
        line_purchase_permitted, reason = line.purchase_info.availability.is_purchase_permitted(total_lines_quantity)
        if not line_purchase_permitted:
            return (line_purchase_permitted, _('Available stock is only %(max)d, which has been exceeded because multiple lines contain the same product.') % {'max': line.purchase_info.availability.num_available})
    if max_allowed is not None and qty > max_allowed:
        return (False, _('Due to technical limitations we are not able to ship more than %(threshold)d items in one order.') % {'threshold': basket_threshold})
    return (True, None)

def get_stock_info(self, product, options):
    """
        Hook for implementing strategies that depend on product options
        """
    return self.strategy.fetch_for_product(product)

def add_product(self, product, quantity=1, options=None):
    """
        Add a product to the basket

        The 'options' list should contains dicts with keys 'option' and 'value'
        which link the relevant product.Option model and string value
        respectively.

        Returns (line, created).
          line: the matching basket line
          created: whether the line was created or updated

        """
    if options is None:
        options = []
    if not self.id:
        self.save()
    price_currency = self.currency
    stock_info = self.get_stock_info(product, options)
    if not stock_info.price.exists:
        raise ValueError("Strategy hasn't found a price for product %s" % product)
    if price_currency and stock_info.price.currency != price_currency:
        raise ValueError('Basket lines must all have the same currency. Proposed line has currency %s, while basket has currency %s' % (stock_info.price.currency, price_currency))
    if stock_info.stockrecord is None:
        raise ValueError("Basket lines must all have stock records. Strategy hasn't found any stock record for product %s" % product)
    line_ref = self._create_line_reference(product, stock_info.stockrecord, options)
    defaults = {'quantity': max(0, quantity), 'price_excl_tax': stock_info.price.excl_tax, 'price_currency': stock_info.price.currency, 'tax_code': stock_info.price.tax_code}
    if stock_info.price.is_tax_known:
        defaults['price_incl_tax'] = stock_info.price.incl_tax
    line, created = self.lines.get_or_create(line_reference=line_ref, product=product, stockrecord=stock_info.stockrecord, defaults=defaults)
    if created:
        for option_dict in options:
            line.attributes.create(option=option_dict['option'], value=option_dict['value'])
    else:
        line.quantity = max(0, line.quantity + quantity)
        line.save()
    self.reset_offer_applications()
    return (line, created)

def merge_line(self, line, add_quantities=True):
    """
        For transferring a line from another basket to this one.

        This is used with the "Saved" basket functionality.
        """
    try:
        existing_line = self.lines.get(line_reference=line.line_reference)
    except ObjectDoesNotExist:
        line.basket = self
        line.save()
    else:
        if add_quantities:
            existing_line.quantity += line.quantity
        else:
            existing_line.quantity = max(existing_line.quantity, line.quantity)
        existing_line.save()
        line.delete()
    finally:
        self._lines = None

def is_shipping_required(self):
    """
        Test whether the basket contains physical products that require
        shipping.
        """
    for line in self.all_lines():
        if line.product.is_shipping_required:
            return True
    return False

def _get_total(self, model_property):
    """
        For executing a named method on each line of the basket
        and returning the total.
        """
    total = D('0.00')
    for line in self.all_lines():
        try:
            total += getattr(line, model_property)
        except ObjectDoesNotExist:
            pass
        except TypeError:
            info = self.get_stock_info(line.product, line.attributes.all())
            if info.availability.is_available_to_buy:
                raise
    return round_half_up_two_dec(total)

