def description(self):
    d = smart_str(self.product)
    ops = []
    for attribute in self.attributes.all():
        value = attribute.value
        if isinstance(value, list):
            ops.append("%s = '%s'" % (attribute.option.name, ', '.join([str(v) for v in value])))
        else:
            ops.append("%s = '%s'" % (attribute.option.name, value))
    if ops:
        d = '%s (%s)' % (d, ', '.join(ops))
    return d

def get_warning(self):
    """
        Return a warning message about this basket line if one is applicable

        This could be things like the price has changed
        """
    if isinstance(self.purchase_info.availability, Unavailable):
        return _("'%(product)s' is no longer available") % {'product': self.product.get_title()}
    if not self.price_incl_tax:
        return
    if not self.purchase_info.price.is_tax_known:
        return
    current_price_incl_tax = self.purchase_info.price.incl_tax
    if current_price_incl_tax != self.price_incl_tax:
        product_prices = {'product': self.product.get_title(), 'old_price': currency(self.price_incl_tax, self.price_currency), 'new_price': currency(current_price_incl_tax, self.price_currency)}
        if current_price_incl_tax > self.price_incl_tax:
            warning = _("The price of '%(product)s' has increased from %(old_price)s to %(new_price)s since you added it to your basket")
            return warning % product_prices
        else:
            warning = _("The price of '%(product)s' has decreased from %(old_price)s to %(new_price)s since you added it to your basket")
            return warning % product_prices

