def process_response(self, request, response):
    cookies_to_delete = getattr(request, 'cookies_to_delete', [])
    for cookie_key in cookies_to_delete:
        response.delete_cookie(cookie_key)
    if not hasattr(request, 'basket'):
        return response
    if isinstance(request.basket, SimpleLazyObject) and request.basket._wrapped is empty:
        return response
    cookie_key = self.get_cookie_key(request)
    has_basket_cookie = cookie_key in request.COOKIES and cookie_key not in cookies_to_delete
    if request.basket.id and (not request.user.is_authenticated) and (not has_basket_cookie):
        cookie = self.get_basket_hash(request.basket.id)
        response.set_cookie(cookie_key, cookie, max_age=settings.OSCAR_BASKET_COOKIE_LIFETIME, secure=settings.OSCAR_BASKET_COOKIE_SECURE, httponly=True)
    return response

def process_template_response(self, request, response):
    if hasattr(response, 'context_data'):
        if response.context_data is None:
            response.context_data = {}
        if 'basket' not in response.context_data:
            response.context_data['basket'] = request.basket
        else:
            response.context_data['request_basket'] = request.basket
    return response

def get_basket(self, request):
    """
        Return the open basket for this request
        """
    if request._basket_cache is not None:
        return request._basket_cache
    num_items_merged = 0
    manager = Basket.open
    cookie_key = self.get_cookie_key(request)
    cookie_basket = self.get_cookie_basket(cookie_key, request, manager)
    if hasattr(request, 'user') and request.user.is_authenticated:
        try:
            basket, __ = manager.get_or_create(owner=request.user)
        except Basket.MultipleObjectsReturned:
            old_baskets = list(manager.filter(owner=request.user))
            basket = old_baskets[0]
            for other_basket in old_baskets[1:]:
                self.merge_baskets(basket, other_basket)
                num_items_merged += other_basket.num_items
        basket.owner = request.user
        if cookie_basket:
            num_items_merged += cookie_basket.num_items
            self.merge_baskets(basket, cookie_basket)
            request.cookies_to_delete.append(cookie_key)
    elif cookie_basket:
        basket = cookie_basket
    else:
        basket = Basket()
    request._basket_cache = basket
    if num_items_merged > 0:
        messages.add_message(request, messages.WARNING, ngettext_lazy('We have merged %(num_items_merged)d item from a previous session to your basket.', 'We have merged %(num_items_merged)d items from a previous session to your basket.', num_items_merged) % {'num_items_merged': num_items_merged})
    return basket

