        """
    return OrderNumberGenerator().order_number(basket)

def update_address_book(self, user, addr):
    """
        Update the user's address book based on the new shipping address
        """
    try:
        user_addr = user.addresses.get(hash=addr.generate_hash())
    except ObjectDoesNotExist:
        user_addr = UserAddress(user=user)
        addr.populate_alternative_model(user_addr)
    if isinstance(addr, ShippingAddress):
        user_addr.num_orders_as_shipping_address += 1
    if isinstance(addr, BillingAddress):
        user_addr.num_orders_as_billing_address += 1
    user_addr.save()

def create_billing_address(self, user, billing_address=None, shipping_address=None, **kwargs):
    """
        Saves any relevant billing data (e.g. a billing address).
        """
    if not billing_address:
        return None
    billing_address.save()
    if user.is_authenticated:
        self.update_address_book(user, billing_address)
    return billing_address

def save_payment_events(self, order):
    """
        Saves any relevant payment events for this order
        """
    if not self._payment_events:
        return
    for event in self._payment_events:
        event.order = order
        event.save()
        for line in order.lines.all():
            PaymentEventQuantity.objects.create(event=event, line=line, quantity=line.quantity)

def get_message_context(self, order):
    ctx = {'user': self.request.user, 'order': order, 'lines': order.lines.all(), 'request': self.request}
    try:
        if self.request.user.is_authenticated:
            path = reverse('customer:order', kwargs={'order_number': order.number})
        else:
            path = reverse('customer:anon-order', kwargs={'order_number': order.number, 'hash': order.verification_hash()})
    except NoReverseMatch:
        pass
    else:
        ctx['status_path'] = path
        site = Site.objects.get_current(self.request)
        ctx['status_url'] = 'http://%s%s' % (site.domain, path)
    return ctx

def get_submitted_basket(self):
    basket_id = self.checkout_session.get_submitted_basket_id()
    return Basket._default_manager.get(pk=basket_id)

def restore_frozen_basket(self):
    """
        Restores a frozen basket as the sole OPEN basket.  Note that this also
        merges in any new products that have been added to a basket that has
        been created while payment.
        """
    try:
        fzn_basket = self.get_submitted_basket()
    except Basket.DoesNotExist:
        pass
    else:
        fzn_basket.thaw()
        if self.request.basket.id != fzn_basket.id:
            fzn_basket.merge(self.request.basket)
            fzn_basket.strategy = self.request.basket.strategy
            self.request.basket = fzn_basket

def dispatch(self, request, *args, **kwargs):
    self.checkout_session = CheckoutSessionData(request)
    try:
        self.check_skip_conditions(request)
    except exceptions.PassedSkipCondition as e:
        return http.HttpResponseRedirect(e.url)
    try:
        self.check_pre_conditions(request)
    except exceptions.FailedPreCondition as e:
        for message in e.messages:
            messages.warning(request, message)
        return http.HttpResponseRedirect(e.url)
    return super().dispatch(request, *args, **kwargs)

def check_pre_conditions(self, request):
    pre_conditions = self.get_pre_conditions(request)
    for method_name in pre_conditions:
        if not hasattr(self, method_name):
            raise ImproperlyConfigured("There is no method '%s' to call as a pre-condition" % method_name)
        getattr(self, method_name)(request)

def check_skip_conditions(self, request):
    skip_conditions = self.get_skip_conditions(request)
    for method_name in skip_conditions:
        if not hasattr(self, method_name):
            raise ImproperlyConfigured("There is no method '%s' to call as a skip-condition" % method_name)
        getattr(self, method_name)(request)

def check_basket_is_not_empty(self, request):
    if request.basket.is_empty:
        raise exceptions.FailedPreCondition(url=reverse('basket:summary'), message=_('You need to add some items to your basket to checkout'))

def check_basket_is_valid(self, request):
    """
        Check that the basket is permitted to be submitted as an order. That
        is, all the basket lines are available to buy - nothing has gone out of
        stock since it was added to the basket.
        """
    messages_list = []
    strategy = request.strategy
    for line in request.basket.all_lines():
        result = strategy.fetch_for_line(line)
        is_permitted, reason = result.availability.is_purchase_permitted(line.quantity)
        if not is_permitted:
            msg = _("'%(title)s' is no longer available to buy (%(reason)s). Please adjust your basket to continue") % {'title': line.product.get_title(), 'reason': reason}
            messages_list.append(msg)
    if messages_list:
        raise exceptions.FailedPreCondition(url=reverse('basket:summary'), messages=messages_list)

def check_user_email_is_captured(self, request):
    if not request.user.is_authenticated and (not self.checkout_session.get_guest_email()):
        raise exceptions.FailedPreCondition(url=reverse('checkout:index'), message=_('Please either sign in or enter your email address'))

def check_shipping_data_is_captured(self, request):
    if not request.basket.is_shipping_required():
        if not self.checkout_session.is_shipping_method_set(self.request.basket):
            raise exceptions.FailedPreCondition(url=reverse('checkout:shipping-method'))
        return
    self.check_a_valid_shipping_address_is_captured()
    self.check_a_valid_shipping_method_is_captured()

def check_a_valid_shipping_address_is_captured(self):
    if not self.checkout_session.is_shipping_address_set():
        raise exceptions.FailedPreCondition(url=reverse('checkout:shipping-address'), message=_('Please choose a shipping address'))
    shipping_address = self.get_shipping_address(basket=self.request.basket)
    if not shipping_address:
        raise exceptions.FailedPreCondition(url=reverse('checkout:shipping-address'), message=_('Your previously chosen shipping address is no longer valid.  Please choose another one'))

def check_a_valid_shipping_method_is_captured(self):
    if not self.checkout_session.is_shipping_method_set(self.request.basket):
        raise exceptions.FailedPreCondition(url=reverse('checkout:shipping-method'), message=_('Please choose a shipping method'))
    shipping_address = self.get_shipping_address(basket=self.request.basket)
    shipping_method = self.get_shipping_method(basket=self.request.basket, shipping_address=shipping_address)
    if not shipping_method:
        raise exceptions.FailedPreCondition(url=reverse('checkout:shipping-method'), message=_('Your previously chosen shipping method is no longer valid.  Please choose another one'))

def skip_unless_basket_requires_shipping(self, request):
    if not request.basket.is_shipping_required():
        raise exceptions.PassedSkipCondition(url=reverse('checkout:shipping-method'))

def skip_unless_payment_is_required(self, request):
    shipping_address = self.get_shipping_address(request.basket)
    shipping_method = self.get_shipping_method(request.basket, shipping_address)
    if shipping_method:
        shipping_charge = shipping_method.calculate(request.basket)
    else:
        shipping_charge = prices.Price(currency=request.basket.currency, excl_tax=D('0.00'), tax=D('0.00'))
    surcharges = SurchargeApplicator(request).get_applicable_surcharges(basket=request.basket, shipping_charge=shipping_charge)
    total = self.get_order_totals(request.basket, shipping_charge, surcharges)
    if total.excl_tax == D('0.00'):
        raise exceptions.PassedSkipCondition(url=reverse('checkout:preview'))

def get_billing_address(self, shipping_address):
    """
        Return an unsaved instance of the billing address (if one exists)

        This method only returns a billing address if the session has been used
        to store billing address information. It's also possible to capture
        billing address information as part of the payment details forms, which
        never get stored in the session. In that circumstance, the billing
        address can be set directly in the build_submission dict.
        """
    if not self.checkout_session.is_billing_address_set():
        return None
    if self.checkout_session.is_billing_address_same_as_shipping():
        if shipping_address:
            address = BillingAddress()
            shipping_address.populate_alternative_model(address)
            return address
    addr_data = self.checkout_session.new_billing_address_fields()
    if addr_data:
        return BillingAddress(**addr_data)
    addr_id = self.checkout_session.billing_user_address_id()
    if addr_id:
        try:
            user_address = UserAddress._default_manager.get(pk=addr_id)
        except UserAddress.DoesNotExist:
            return None
        else:
            billing_address = BillingAddress()
            user_address.populate_alternative_model(billing_address)
            return billing_address

def get_order_totals(self, basket, shipping_charge, surcharges=None, **kwargs):
    """
        Returns the total for the order with and without tax
        """
    return OrderTotalCalculator(self.request).calculate(basket, shipping_charge, surcharges, **kwargs)

def calculate(self, basket, **kwargs):
    if not basket.is_empty:
        shipping_charge = kwargs.get('shipping_charge')
        if shipping_charge is not None:
            total_excl_tax = basket.total_excl_tax + shipping_charge.excl_tax
            total_incl_tax = basket.total_incl_tax + shipping_charge.incl_tax
        else:
            total_excl_tax = basket.total_excl_tax
            total_incl_tax = basket.total_incl_tax
        return prices.Price(currency=basket.currency, excl_tax=total_excl_tax * self.percentage / 100, incl_tax=total_incl_tax * self.percentage / 100)
    else:
        return prices.Price(currency=basket.currency, excl_tax=D('0.0'), incl_tax=D('0.0'))

