def submit(self, user, basket, shipping_address, shipping_method, shipping_charge, billing_address, order_total, payment_kwargs=None, order_kwargs=None, surcharges=None):
    """
        Submit a basket for order placement.

        The process runs as follows:

         * Generate an order number
         * Freeze the basket so it cannot be modified any more (important when
           redirecting the user to another site for payment as it prevents the
           basket being manipulated during the payment process).
         * Attempt to take payment for the order
           - If payment is successful, place the order
           - If a redirect is required (e.g. PayPal, 3D Secure), redirect
           - If payment is unsuccessful, show an appropriate error message

        :basket: The basket to submit.
        :payment_kwargs: Additional kwargs to pass to the handle_payment
                         method. It normally makes sense to pass form
                         instances (rather than model instances) so that the
                         forms can be re-rendered correctly if payment fails.
        :order_kwargs: Additional kwargs to pass to the place_order method
        """
    if payment_kwargs is None:
        payment_kwargs = {}
    if order_kwargs is None:
        order_kwargs = {}
    assert basket.is_tax_known, 'Basket tax must be set before a user can place an order'
    assert shipping_charge.is_tax_known, 'Shipping charge tax must be set before a user can place an order'
    order_number = self.generate_order_number(basket)
    self.checkout_session.set_order_number(order_number)
    logger.info('Order #%s: beginning submission process for basket #%d', order_number, basket.id)
    self.freeze_basket(basket)
    self.checkout_session.set_submitted_basket(basket)
    error_msg = _('A problem occurred while processing payment for this order - no payment has been taken.  Please contact customer services if this problem persists')
    signals.pre_payment.send_robust(sender=self, view=self)
    try:
        self.handle_payment(order_number, order_total, **payment_kwargs)
    except RedirectRequired as e:
        logger.info('Order #%s: redirecting to %s', order_number, e.url)
        return http.HttpResponseRedirect(e.url)
    except UnableToTakePayment as e:
        msg = str(e)
        logger.warning('Order #%s: unable to take payment (%s) - restoring basket', order_number, msg)
        self.restore_frozen_basket()
        return self.render_payment_details(self.request, error=msg, **payment_kwargs)
    except PaymentError as e:
        msg = str(e)
        logger.error('Order #%s: payment error (%s)', order_number, msg, exc_info=True)
        self.restore_frozen_basket()
        return self.render_preview(self.request, error=error_msg, **payment_kwargs)
    except Exception as e:
        logger.exception('Order #%s: unhandled exception while taking payment (%s)', order_number, e)
        self.restore_frozen_basket()
        return self.render_preview(self.request, error=error_msg, **payment_kwargs)
    signals.post_payment.send_robust(sender=self, view=self)
    logger.info('Order #%s: payment successful, placing order', order_number)
    try:
        return self.handle_order_placement(order_number, user, basket, shipping_address, shipping_method, shipping_charge, billing_address, order_total, surcharges=surcharges, **order_kwargs)
    except UnableToPlaceOrder as e:
        msg = str(e)
        logger.error('Order #%s: unable to place order - %s', order_number, msg, exc_info=True)
        self.restore_frozen_basket()
        return self.render_preview(self.request, error=msg, **payment_kwargs)
    except Exception as e:
        logger.exception('Order #%s: unhandled exception while placing order (%s)', order_number, e)
        error_msg = _('A problem occurred while placing this order. Please contact customer services.')
        self.restore_frozen_basket()
        return self.render_preview(self.request, error=error_msg, **payment_kwargs)

