def _orders_description(self, date_from, date_to, order_number):
    if date_from and date_to:
        if order_number:
            desc = _('Orders placed between %(date_from)s and %(date_to)s and order number containing %(order_number)s')
        else:
            desc = _('Orders placed between %(date_from)s and %(date_to)s')
    elif date_from:
        if order_number:
            desc = _('Orders placed since %(date_from)s and order number containing %(order_number)s')
        else:
            desc = _('Orders placed since %(date_from)s')
    elif date_to:
        if order_number:
            desc = _('Orders placed until %(date_to)s and order number containing %(order_number)s')
        else:
            desc = _('Orders placed until %(date_to)s')
    elif order_number:
        desc = _('Orders with order number containing %(order_number)s')
    else:
        return None
    params = {'date_from': date_from, 'date_to': date_to, 'order_number': order_number}
    return desc % params

