def create_menu(menu_items, parent=None):
    """
    Create the navigation nodes based on a passed list of dicts
    """
    nodes = []
    default_fn = import_string(settings.OSCAR_DASHBOARD_DEFAULT_ACCESS_FUNCTION)
    for menu_dict in menu_items:
        try:
            label = menu_dict['label']
        except KeyError:
            raise ImproperlyConfigured('No label specified for menu item in dashboard')
        children = menu_dict.get('children', [])
        if children:
            node = Node(label=label, icon=menu_dict.get('icon', None), access_fn=menu_dict.get('access_fn', default_fn))
            create_menu(children, parent=node)
        else:
            node = Node(label=label, icon=menu_dict.get('icon', None), url_name=menu_dict.get('url_name', None), url_kwargs=menu_dict.get('url_kwargs', None), url_args=menu_dict.get('url_args', None), access_fn=menu_dict.get('access_fn', default_fn))
        if parent is None:
            nodes.append(node)
        else:
            parent.add_child(node)
    return nodes

@lru_cache(maxsize=1)
def _dashboard_url_names_to_config():
    dashboard_configs = (config for config in apps.get_app_configs() if isinstance(config, OscarDashboardConfig))
    urls_to_config = {}
    for config in dashboard_configs:
        for url in config.urls[0]:
            name = getattr(url, 'name', None)
            if not name:
                continue
            if name in urls_to_config:
                if urls_to_config[name] != config:
                    raise ImproperlyConfigured("'{}' exists in both {} and {}!".format(name, config, urls_to_config[name]))
            urls_to_config[name] = config
    return urls_to_config

