@cached_property
def product_queryset(self):
    """cached queryset of all the products in the Range"""
    ProductCategoryHierarchy = get_model('catalogue', 'ProductCategoryHierarchy')
    Product = self.included_products.model
    if self.includes_all_products:
        _filter = Q(id__in=self.excluded_products.values('id'))
        if self.excluded_categories.exists():
            if use_productcategory_materialised_view():
                product_ids = ProductCategoryHierarchy.objects.filter(category_id__in=self.excluded_categories.values_list('id', flat=True)).values_list('product_id', flat=True)
                _filter |= Q(id__in=product_ids)
                _filter |= Q(parent__id__in=product_ids)
            else:
                expanded_range_categories = ExpandDownwardsCategoryQueryset(self.excluded_categories.values('id'))
                _filter |= Q(categories__in=expanded_range_categories)
                if Product.objects.exclude(parent=None).filter(parent__categories__in=expanded_range_categories).exists():
                    _filter |= Q(parent__categories__in=expanded_range_categories)
        return Product.objects.exclude(_filter)
    _filter = Q(includes=self)
    if Product.objects.filter(parent__includes=self).exists():
        _filter |= Q(parent__includes=self)
    if self.classes.exists():
        _filter |= Q(product_class__classes=self)
        _filter |= Q(parent__product_class__classes=self)
    if self.included_categories.exists():
        if use_productcategory_materialised_view():
            product_ids = ProductCategoryHierarchy.objects.filter(category_id__in=self.included_categories.values_list('id', flat=True)).values_list('product_id', flat=True)
            _filter |= Q(id__in=product_ids)
            _filter |= Q(parent__id__in=product_ids)
        else:
            expanded_range_categories = ExpandDownwardsCategoryQueryset(self.included_categories.values('id'))
            _filter |= Q(categories__in=expanded_range_categories)
            if Product.objects.exclude(parent=None).filter(parent__categories__in=expanded_range_categories).exists():
                _filter |= Q(parent__categories__in=expanded_range_categories)
    qs = Product.objects.filter(_filter, ~Q(excludes=self))
    if Product.objects.filter(parent__excludes=self).exists():
        qs = qs.filter(~Q(parent__excludes=self))
    return qs.distinct()

