    self._num_matches = num_matches
    return num_matches

def is_partially_satisfied(self, offer, basket):
    num_matches = self._get_num_matches(basket, offer)
    return 0 < num_matches < self.value

def get_upsell_message(self, offer, basket):
    num_matches = self._get_num_matches(basket, offer)
    delta = self.value - num_matches
    if delta > 0:
        return ngettext('Buy %(delta)d more product from %(range)s', 'Buy %(delta)d more products from %(range)s', int(delta)) % {'delta': delta, 'range': self.range}

