@classmethod
def random_key(cls, length=6):
    """
        Get a unique random generated key
        """
    while True:
        key = get_random_string(length=length, allowed_chars='abcdefghijklmnopqrstuvwxyz0123456789')
        if not cls._default_manager.filter(key=key).exists():
            return key

