def clean(self):
    """
        If the user isn't a staff user, this validation ensures that at least
        one stock record's partner is associated with a users partners.
        """
    if any(self.errors):
        return
    if self.require_user_stockrecord:
        stockrecord_partners = set([form.cleaned_data.get('partner', None) for form in self.forms])
        user_partners = set(self.user.partners.all())
        if not user_partners & stockrecord_partners:
            raise exceptions.ValidationError(_("At least one stock record must be set to a partner that you're associated with."))

def clean(self):
    if not self.instance.is_child and self.get_num_categories() == 0:
        raise forms.ValidationError(_('Stand-alone and parent products must have at least one category'))
    if self.instance.is_child and self.get_num_categories() > 0:
        raise forms.ValidationError(_('A child product should not have categories'))

def get_num_categories(self):
    num_categories = 0
    for i in range(0, self.total_form_count()):
        form = self.forms[i]
        if hasattr(form, 'cleaned_data') and form.cleaned_data.get('category', None) and (not form.cleaned_data.get('DELETE', False)):
            num_categories += 1
    return num_categories

