def get_changes_between_models(model1, model2, excludes=None):
    """
    Return a dict of differences between two model instances
    """
    if excludes is None:
        excludes = []
    changes = {}
    for field in model1._meta.fields:
        if isinstance(field, (fields.AutoField, fields.related.RelatedField)) or field.name in excludes:
            continue
        if field.value_from_object(model1) != field.value_from_object(model2):
            changes[field.verbose_name] = (field.value_from_object(model1), field.value_from_object(model2))
    return changes

def get_change_summary(model1, model2):
    """
    Generate a summary of the changes between two address models
    """
    changes = get_changes_between_models(model1, model2, ['search_text'])
    change_descriptions = []
    for field, delta in changes.items():
        change_descriptions.append(_("%(field)s changed from '%(old_value)s' to '%(new_value)s'") % {'field': field, 'old_value': delta[0], 'new_value': delta[1]})
    return '\n'.join(change_descriptions)

