def get_queryset(self):
    """
        Build the queryset for this list.
        """
    queryset = sort_queryset(self.base_queryset, self.request, ['number', 'total_incl_tax'])
    self.form = self.form_class(self.request.GET)
    if not self.form.is_valid():
        return queryset
    data = self.form.cleaned_data
    if data['order_number']:
        queryset = self.base_queryset.filter(number__istartswith=data['order_number'])
    if data['name']:
        parts = data['name'].split()
        allow_anon = getattr(settings, 'OSCAR_ALLOW_ANON_CHECKOUT', False)
        if len(parts) == 1:
            parts = [data['name'], data['name']]
        else:
            parts = [parts[0], parts[1:]]
        query = Q(user__first_name__istartswith=parts[0])
        query |= Q(user__last_name__istartswith=parts[1])
        if allow_anon:
            query |= Q(billing_address__first_name__istartswith=parts[0])
            query |= Q(shipping_address__first_name__istartswith=parts[0])
            query |= Q(billing_address__last_name__istartswith=parts[1])
            query |= Q(shipping_address__last_name__istartswith=parts[1])
        queryset = queryset.filter(query).distinct()
    if data['product_title']:
        queryset = queryset.filter(lines__title__istartswith=data['product_title']).distinct()
    if data['upc']:
        queryset = queryset.filter(lines__upc=data['upc'])
    if data['partner_sku']:
        queryset = queryset.filter(lines__partner_sku=data['partner_sku'])
    if data['date_from'] and data['date_to']:
        date_to = datetime_combine(data['date_to'], datetime.time.max)
        date_from = datetime_combine(data['date_from'], datetime.time.min)
        queryset = queryset.filter(date_placed__gte=date_from, date_placed__lt=date_to)
    elif data['date_from']:
        date_from = datetime_combine(data['date_from'], datetime.time.min)
        queryset = queryset.filter(date_placed__gte=date_from)
    elif data['date_to']:
        date_to = datetime_combine(data['date_to'], datetime.time.max)
        queryset = queryset.filter(date_placed__lt=date_to)
    if data['voucher']:
        queryset = queryset.filter(discounts__voucher_code=data['voucher']).distinct()
    if data['payment_method']:
        queryset = queryset.filter(sources__source_type__code=data['payment_method']).distinct()
    if data['status']:
        queryset = queryset.filter(status=data['status'])
    return queryset

def get_search_filter_descriptions(self):
    """Describe the filters used in the search.

        These are user-facing messages describing what filters
        were used to filter orders in the search query.

        Returns:
            list of unicode messages

        """
    descriptions = []
    data = getattr(self.form, 'cleaned_data', None)
    if data is None:
        return descriptions
    if data.get('order_number'):
        descriptions.append(_('Order number starts with "{order_number}"').format(order_number=data['order_number']))
    if data.get('name'):
        descriptions.append(_('Customer name matches "{customer_name}"').format(customer_name=data['name']))
    if data.get('product_title'):
        descriptions.append(_('Product name matches "{product_name}"').format(product_name=data['product_title']))
    if data.get('upc'):
        descriptions.append(_('Includes an item with UPC "{upc}"').format(upc=data['upc']))
    if data.get('partner_sku'):
        descriptions.append(_('Includes an item with partner SKU "{partner_sku}"').format(partner_sku=data['partner_sku']))
    if data.get('date_from') and data.get('date_to'):
        descriptions.append(_('Placed between {start_date} and {end_date}').format(start_date=data['date_from'], end_date=data['date_to']))
    elif data.get('date_from'):
        descriptions.append(_('Placed after {start_date}').format(start_date=data['date_from']))
    elif data.get('date_to'):
        end_date = data['date_to'] + datetime.timedelta(days=1)
        descriptions.append(_('Placed before {end_date}').format(end_date=end_date))
    if data.get('voucher'):
        descriptions.append(_('Used voucher code "{voucher_code}"').format(voucher_code=data['voucher']))
    if data.get('payment_method'):
        payment_type = SourceType.objects.get(code=data['payment_method'])
        descriptions.append(_('Paid using {payment_method}').format(payment_method=payment_type.name))
    if data.get('status'):
        descriptions.append(_('Order status is {order_status}').format(order_status=data['status']))
    return descriptions

