def add_products(self, request):
    product_range = self.get_product_range()
    form = self.form_class(product_range, request.POST, request.FILES)
    if not form.is_valid():
        ctx = self.get_context_data(form=form, object_list=self.object_list)
        return self.render_to_response(ctx)
    self.handle_query_products(request, product_range, form)
    self.handle_file_products(request, product_range, form)
    return redirect(reverse('dashboard:range-products', kwargs={'pk': product_range.pk}))

def add_excluded_products(self, request):
    product_range = self.get_product_range()
    form = self.form_class(product_range, request.POST, request.FILES, initial={'upload_type': RangeProductFileUpload.EXCLUDED_PRODUCTS_TYPE})
    if not form.is_valid():
        ctx = self.get_context_data(form_excluded=form, object_list=self.object_list)
        return self.render_to_response(ctx)
    self.handle_query_products(request, product_range, form)
    self.handle_file_products(request, product_range, form)
    return redirect(reverse('dashboard:range-products', kwargs={'pk': product_range.pk}) + '?upload_type=excluded')

def remove_excluded_products(self, request):
    product_ids = request.POST.getlist('selected_product', None)
    products = self.model.objects.filter(id__in=product_ids)
    product_range = self.get_product_range()
    for product in products:
        product_range.excluded_products.remove(product)
    num_products = len(products)
    messages.success(request, ngettext('Removed %d product from excluded list', 'Removed %d products from excluded list', num_products) % num_products)
    return redirect(reverse('dashboard:range-products', kwargs={'pk': product_range.pk}) + '?upload_type=excluded')

def handle_query_products(self, request, product_range, form):
    products = form.get_products()
    if not products:
        return
    for product in products:
        if form.cleaned_data['upload_type'] == RangeProductFileUpload.EXCLUDED_PRODUCTS_TYPE:
            product_range.excluded_products.add(product)
            action = _('excluded from this range')
        else:
            product_range.add_product(product)
            action = _('added to this range')
    num_products = len(products)
    messages.success(request, ngettext('%(num_products)d product has been %(action)s', '%(num_products)d products have been %(action)s', num_products) % {'num_products': num_products, 'action': action})
    dupe_skus = form.get_duplicate_skus()
    if dupe_skus:
        messages.warning(request, _('The products with SKUs or UPCs matching %(skus)s have already been %(action)s') % {'skus': ', '.join(dupe_skus), 'action': action})
    missing_skus = form.get_missing_skus()
    if missing_skus:
        messages.warning(request, _('No product(s) were found with SKU or UPC matching %s') % ', '.join(missing_skus))
    self.check_imported_products_sku_duplicates(request, products)

def handle_file_products(self, request, product_range, form):
    if 'file_upload' not in request.FILES:
        return
    f = request.FILES['file_upload']
    upload = self.create_upload_object(request, product_range, f, form.cleaned_data['upload_type'])
    products = upload.process(TextIOWrapper(f, encoding=request.encoding))
    if not upload.was_processing_successful():
        messages.error(request, upload.error_message)
    else:
        if form.cleaned_data['upload_type'] == RangeProductFileUpload.EXCLUDED_PRODUCTS_TYPE:
            action = 'excluded from this range'
        else:
            action = 'added to this range'
        msg = render_to_string('oscar/dashboard/ranges/messages/range_products_saved.html', {'range': product_range, 'upload': upload, 'action': action})
        messages.success(request, msg, extra_tags='safe noicon block')
    self.check_imported_products_sku_duplicates(request, products)

def create_upload_object(self, request, product_range, f, upload_type):
    upload = RangeProductFileUpload.objects.create(range=product_range, uploaded_by=request.user, filepath=f.name, size=f.size, upload_type=upload_type)
    return upload

def check_imported_products_sku_duplicates(self, request, queryset):
    dupe_sku_products = queryset.values('stockrecords__partner_sku').annotate(total=Count('stockrecords__partner_sku')).filter(total__gt=1).order_by('stockrecords__partner_sku')
    if dupe_sku_products:
        dupe_skus = [p['stockrecords__partner_sku'] for p in dupe_sku_products]
        messages.warning(request, _('There are more than one product with SKU %s') % ', '.join(dupe_skus))

