    data = self.form.cleaned_data
    if data['status']:
        queryset = queryset.filter(status=data['status'])
        self.description += _(" with status matching '%s'") % data['status']
    if data['name']:
        parts = data['name'].split()
        if len(parts) >= 2:
            queryset = queryset.filter(user__first_name__istartswith=parts[0], user__last_name__istartswith=parts[1]).distinct()
        else:
            queryset = queryset.filter(Q(user__first_name__istartswith=parts[0]) | Q(user__last_name__istartswith=parts[-1])).distinct()
        self.description += _(" with customer name matching '%s'") % data['name']
    if data['email']:
        queryset = queryset.filter(Q(user__email__icontains=data['email']) | Q(email__icontains=data['email']))
        self.description += _(" with customer email matching '%s'") % data['email']
    return queryset

