    post_params = {'product_id': dummy_product.id, 'action': 'add', 'quantity': 2}
    response = self.app.post(url, params=post_params)
    expected = gettext('Due to technical limitations we are not able to ship more than %(threshold)d items in one order. Your basket currently has %(basket)d items.') % {'threshold': 3, 'basket': 2}
    if django.VERSION < (3, 2):
        self.assertIn(expected, response.test_app.cookies['messages'])
    else:
        signer = signing.get_cookie_signer(salt='django.contrib.messages')
        message_strings = [m.message for m in signer.unsign_object(response.test_app.cookies['messages'], serializer=cookie.MessageSerializer)]
        self.assertIn(expected, message_strings)

