def safe_exec(self, string, value=None, context=None):
    loc = {}
    g = globals()
    g.update(context)
    try:
        exec(string, g, loc)
    except Exception as e:
        if value:
            self.fail('Could not exec %r (from value %r): %s' % (string.strip(), value, e))
        else:
            self.fail('Could not exec %r: %s' % (string.strip(), e))
    return loc

