def test_get_attribute_values_prefetch(self):
    for _ in range(5):
        parent = ProductFactory(structure='parent', stockrecords=[])
        for _ in range(3):
            ProductAttributeValueFactory(product=parent)
        for _ in range(5):
            child = ProductFactory(structure='child', parent=parent, stockrecords=[])
            for _ in range(3):
                ProductAttributeValueFactory(product=child)
    with self.assertNumQueries(56):
        products = Product.objects.all()
        for product in products:
            list(product.get_attribute_values())
    with self.assertNumQueries(7):
        products = Product.objects.prefetch_attribute_values()
        for product in products:
            list(product.get_attribute_values())
    prefetched_products = list(Product.objects.prefetch_attribute_values())
    for product in prefetched_products:
        if product.is_child:
            child_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
            parent_attr_codes = set((av.attribute.code for av in product.parent.attribute_values.all()))
            prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
            self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
        else:
            own_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
            prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
            self.assertEqual(prefetched_attr_codes, own_attr_codes)

def test_get_attribute_values_prefetch_including_child_attributes(self):
    for _ in range(5):
        parent = ProductFactory(structure='parent', stockrecords=[])
        for _ in range(3):
            ProductAttributeValueFactory(product=parent)
        for _ in range(5):
            child = ProductFactory(structure='child', parent=parent, stockrecords=[])
            for _ in range(3):
                ProductAttributeValueFactory(product=child)
    with self.assertNumQueries(86):
        products = Product.objects.all()
        for product in products:
            list(product.get_attribute_values())
            if product.is_parent:
                for child in product.children.all():
                    list(child.get_attribute_values())
    with self.assertNumQueries(37):
        products = Product.objects.prefetch_attribute_values()
        for product in products:
            list(product.get_attribute_values())
            if product.is_parent:
                for child in product.children.all():
                    list(child.get_attribute_values())
    with self.assertNumQueries(12):
        products = Product.objects.prefetch_attribute_values(include_parent_children_attributes=True)
        for product in products:
            list(product.get_attribute_values())
            if product.is_parent:
                for child in product.children.all():
                    list(child.get_attribute_values())
    prefetched_products = list(Product.objects.prefetch_attribute_values(include_parent_children_attributes=True))
    for product in prefetched_products:
        if product.is_child:
            child_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
            parent_attr_codes = set((av.attribute.code for av in product.parent.attribute_values.all()))
            prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
            self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
            self.assertEqual(prefetched_attr_codes, child_attr_codes.union(parent_attr_codes))
        else:
            own_attr_codes = set((av.attribute.code for av in product.attribute_values.all()))
            prefetched_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
            self.assertEqual(prefetched_attr_codes, own_attr_codes)
            if product.is_parent:
                for child in product.children.all():
                    child_attr_codes = set((av.attribute.code for av in child.attribute_values.all()))
                    combined_attr_codes = set((av.attribute.code for av in product.get_attribute_values()))
                    self.assertEqual(combined_attr_codes, own_attr_codes.union(child_attr_codes))

