def test_anchor_tag_output(self):
    ctx = {'request': RequestFactory().get('/')}
    self.assertEqual(anchor(ctx, 'foo'), '<a href="/?sort=foo">Foo</a>')
    self.assertEqual(anchor(ctx, 'foo', 'Title'), '<a href="/?sort=foo">Title</a>')
    self.assertEqual(anchor(ctx, 'foo', 'Ti&tle'), '<a href="/?sort=foo">Ti&amp;tle</a>')
    ctx = {'request': RequestFactory().get('/?sort=foo&dir=asc')}
    self.assertEqual(anchor(ctx, 'foo'), '<a href="/?sort=foo&dir=desc">Foo <i class="fas fa-chevron-up"></i></a>')

def is_satisfied(self, offer, basket):
    if not basket.owner:
        return False
    return basket.owner.first_name.lower() == 'barry'

@property
def description(self):
    return self.name

def get_urls(self):
    from .views import ParentProductDetailView
    urls = super().get_urls()
    urls += [re_path('^parent/(?P<product_slug>[\\w-]*)_(?P<pk>\\d+)/$', ParentProductDetailView.as_view(), name='parent_detail')]
    return self.post_process_urls(urls)

def is_applicable(self, surcharge, basket, **kwargs):
    if surcharge.incl_tax > surcharge.excl_tax:
        if basket.is_tax_known:
            return True
    else:
        return True
    return False

def remove_ancestor_slugs(apps, schema_editor):
    MigrationCategory = apps.get_model('catalogue', 'Category')
    for category in MigrationCategory.objects.all():
        category.slug = category.slug.split(ORMCategory._slug_separator)[-1]
        category.save()

def add_ancestor_slugs(apps, schema_editor):
    MigrationCategory = apps.get_model('catalogue', 'Category')
    for category in MigrationCategory.objects.all():
        orm_category = ORMCategory.objects.get(pk=category.pk)
        category.slug = orm_category.full_slug
        category.save()

def drop_materialized_view(apps, schema_editor):
    """Drops the materialized view if rolling back."""
    if is_postgres():
        with connection.cursor() as cursor:
            cursor.execute('DROP MATERIALIZED VIEW IF EXISTS catalogue_product_category_hierarchy;')
            cursor.execute('DROP INDEX IF EXISTS catalogue_product_category_hierarchy_idx;')
